    key: str = Field(description='The key of the definition. This is used to uniquely identify the definition')
    package: Optional[str] = Field(default=None, description="The package of the function. Will default to the currents agent's app if not specified. This is used to group definitions together in the UI and provide a better user experience")
    version: str = Field(description='The version of the definition. This is used to differentiate if the underyling algorithm has changed, i.e we would expect different results for the same input')
    name: str = Field(description='The name of the actions. This is used to uniquely identify the definition')
    stateful: Annotated[Optional[bool], GraphQLDefault('False')] = Field(default=None, description='Whether the definition is stateful or not. If the definition is stateful, it can be used to create a stateful action. If the definition is not stateful, it cannot be used to create a stateful action')
    'Whether the definition is stateful or not. If the definition is stateful, it can be used to create a stateful action. If the definition is not stateful, it cannot be used to create a stateful action\nDefault: False'
    pure: Annotated[Optional[bool], GraphQLDefault('False')] = Field(default=None, description='Whether the action is pure: same args always produce the same result and no side effects — its results are replayable/cacheable. Implies idempotent. Incompatible with stateful and with a PHYSICAL effect class.')
    'Whether the action is pure: same args always produce the same result and no side effects — its results are replayable/cacheable. Implies idempotent. Incompatible with stateful and with a PHYSICAL effect class.\nDefault: False'
    idempotent: Annotated[Optional[bool], GraphQLDefault('False')] = Field(default=None, description='Whether the action is idempotent: safe to run multiple times with the same args without changing the outcome — on ambiguous executor loss it may be freely re-dispatched.')
    'Whether the action is idempotent: safe to run multiple times with the same args without changing the outcome — on ambiguous executor loss it may be freely re-dispatched.\nDefault: False'
    port_groups: Annotated[Optional[Tuple['PortGroupInput', ...]], GraphQLDefault('[]')] = Field(alias='portGroups', default=None, description='The port groups of the definition. This is used to group ports together in the UI')
    'The port groups of the definition. This is used to group ports together in the UI\nDefault: []'
