    dependencies: Annotated[Optional[Tuple[str, ...]], GraphQLDefault('[]')] = Field(default=None, description="The dependencies of the effect. Use the .. syntax to traverse the tree of ports. For example, if you have a port with the key 'foo' and you want to reference a port with the key 'bar' that is a child of 'foo', you would use 'foo..bar'")
