    message: Optional[str] = Field(default=None, description='The message to display when the effect is applied (if it is a message effect)')
    kind: EffectKind = Field(description='The kind of the effect. Can be either message, hide or custom')
    fade: Annotated[Optional[bool], GraphQLDefault('True')] = Field(default=None, description='Whether to fade out the port when the effect is applied (if it is a hide effect)')
    'Whether to fade out the port when the effect is applied (if it is a hide effect)\nDefault: True'
    hook: Optional[str] = Field(default=None, description='The hook to run when the effect is applied (if it is a custom effect)')
