class ReturnPortInput(PortTrait, BaseModel):
    """Port

    A Port is a single input or output of a action. It is composed of a key and a kind
    which are used to uniquely identify the port.

    If the Port is a structure, we need to define a identifier and scope,
    Identifiers uniquely identify a specific type of model for the scopes (e.g
    all the ports that have the identifier "@mikro/image" are of the same type, and
    are hence compatible with each other). Scopes are used to define in which context
    the identifier is valid (e.g. a port with the identifier "@mikro/image" and the
    scope "local", can only be wired to other ports that have the same identifier and
    are running in the same app). Global ports are ports that have the scope "global",
    and can be wired to any other port that has the same identifier, as there exists a
    mechanism to resolve and retrieve the object for each app. Please check the rekuest
    documentation for more information on how this works.


    """
    validators: Optional[Tuple['ValidatorInput', ...]] = Field(default=None, description='The validators for the port')
    key: str = Field(description='The key of the port')
    label: Optional[str] = Field(default=None, description='The label of the port. This is the text that is displayed in the UI')
    kind: PortKind = Field(description='The kind of the port. This is the type of the port. Can be either int, string, structure, list, bool, dict, float, date, union or model')
    description: Optional[str] = Field(default=None, description='The description of the port. This is the text that is displayed in the UI when the user hovers over the port')
    identifier: Optional[str] = Field(default=None, description='The identifier of a structure port. This is used to uniquely identify a specific type of structure.')
    nullable: Annotated[Optional[bool], GraphQLDefault('False')] = Field(default=None, description='Whether the port is nullable or not. If the port is nullable, it can be set to null. If the port is not nullable, it cannot be set to null')
    'Whether the port is nullable or not. If the port is nullable, it can be set to null. If the port is not nullable, it cannot be set to null\nDefault: False'
    effects: Optional[Tuple[EffectInput, ...]] = Field(default=None, description='The effects of the port')
    default: Optional[Any] = Field(default=None, description='The default value for the port.')
    choices: Optional[Tuple[ChoiceInput, ...]] = Field(default=None, description='The options for the port. This is used for dropdowns and text inputs')
    reference_unit: Optional[str] = Field(alias='referenceUnit', default=None, description='For QUANTITY ports: the canonical/reference unit of the physical quantity, e.g. "volt" or "farad". It is the default selection and the key used to resolve the concrete quantity type; other units of the same dimension are still allowed.')
    proposed_units: Optional[Tuple[str, ...]] = Field(alias='proposedUnits', default=None, description='For QUANTITY ports: units offered as a dropdown in the UI, e.g. ["pF", "nF", "uF"]. Proposals only — any unit of the same dimension remains valid input.')
    dimension: Optional[str] = Field(default=None, description='For QUANTITY ports: the pint dimensionality string, e.g. "[mass] * [length] ** 2 / [time] ** 3 / [current]". This is the wiring-compatibility key between quantity ports.')
