    step: Optional[int] = Field(default=None, description='The step value to display (if a slider).')
    placeholder: Optional[str] = Field(default=None, description='The placeholder text of the return widget.')
    hook: Optional[str] = Field(default=None, description='The hook to run (if it is a custom return widget).')
